settings.custom_liquid:
{% unless product.tags contains "TPO-HEMA" %}
  <div class="hema-tpo-label">
    <img src="https://cdn.shopify.com/s/files/1/0852/1148/0367/files/HemaFree-VERE.png?v=1778660810" alt="Hema Free" class="hema-tpo-icon">
    HEMA Free
    <img src="https://cdn.shopify.com/s/files/1/0852/1148/0367/files/TPOFree-VERDE.png?v=1778660810" alt="TPO Free" class="hema-tpo-icon">
    TPO Free
  </div>

  <style>
    .hema-tpo-label {
      display: flex;
      align-items: center;
      gap: 6px;
    }

    .hema-tpo-icon {
      width: 20px;
      height: 20px;
      object-fit: contain;
    }
  </style>
{% endunless %}

{% if product.metafields.custom.sezione_custom == true %}
  <div 
    style="
      background-color: #f9f8f2;
      border: 1px solid #006450;
      border-radius: 20px;
      padding: 16px;
      color: #006450;
      font-family: 'Poppins', sans-serif;
      font-size: 15px;
      line-height: 1.4;
    "
  >
    <b class="academytitle" style="margin-bottom:10px;">CACTUS ACADEMY</b><br>

    {% if product.handle contains 'liquid-gel' %}
      Acquistando questo prodotto potrai accedere alla nostra video lezione dedicata.<br>

    {% else %}
      Scopri come utilizzare al meglio questo prodotto con la nostra video lezione dedicata.<br>
      <u><a href="https://cactusforyou.com/pages/cactus-for-you-academy"><b>Guarda ora il video</b></a></u>
    {% endif %}
  </div>
{% endif %}

{% if product.metafields.custom.lookbook %}
  <a href="{{ product.metafields.custom.lookbook | escape }}" 
     style="
       display: block;
       width: 100%;
       padding: 9px 10px; /* Reduced padding for a slimmer look */
       background-color: #f9f8f2;
       border: 1px solid #006450;
       border-radius: 50px;
       color: #006450;
       text-decoration: none;
       text-align: center;
       font-size: 15px;
       font-family: 'Poppins', sans-serif;
       transition: background-color 0.3s, color 0.3s;
     "
     target="_blank">
    Scopri l'intera collezione
  </a>
{% endif %}
